<span class="line">      console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;Key pressed: &#39;</span> <span class="token operator">+</span> keyCode<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
